sys_script_include.script:
var PatientUtils = Class.create();
PatientUtils.prototype = {
    initialize: function(patientId) {
		this.patientId = patientId;
    },
	// a. Fetch all patient details by patient ID (sys_id)
  getPatientById: function(patientId) {
    var gr = new GlideRecord('u_patient_record');
    if (gr.get(patientId)) {
      return gr;
    }
    return null;
  },

  // b. Check if a patient is a VIP
  isVip: function(patientId) {
    var gr = this.getPatientById(patientId);
    return gr != null && gr.u_vip == true;
  },

  // c. Calculate the patient's age (years)
  calculateAge: function(patientId) {
    var gr = this.getPatientById(patientId);
    if (!gr || !gr.u_dob) return 0;
    var dob = new GlideDateTime(gr.u_date_of_birth);
    var now = new GlideDateTime();
    var diff = GlideDateTime.subtract(now, dob);  // returns milliseconds
    return Math.floor(diff.getNumericValue() / (365 * 24 * 60 * 60 * 1000));
  },

  // d. Fetch patient's appointments
  getAppointments: function(patientId) {
    var arr = [];
    var gr = new GlideRecord('u_appointment');
    gr.addQuery('u_patient_id.u_number', patientId);
    gr.query();
    while (gr.next()) {
      arr.push({
        sys_id: gr.getUniqueValue(),
        number: gr.getDisplayValue('u_number'),
        status: gr.u_status + ''
      });
    }
    return arr;
  },

  // e. Fetch patient's medications
  getMedications: function(patientId) {
    var arr = [];
    var gr = new GlideRecord('u_medication');
    gr.addQuery('u_patient_id.u_number', patientId);
    gr.query();
    while (gr.next()) {
      arr.push({
        name: gr.getDisplayValue('u_name'),
        dosage: gr.u_dosage + '',
        frequency: gr.u_frequency + ''
      });
    }
    return arr;
  },

  // f. Fetch patient's lab tests
  getLabTests: function(patientId) {
    var arr = [];
    var gr = new GlideRecord('u_lab_test');
    gr.addQuery('u_patient_id.u_number', patientId);
    gr.query();
    while (gr.next()) {
      arr.push({
        number: gr.getDisplayValue('u_number'),
        result: gr.u_result + ''
      });
    }
    return arr;
  },

  // g. Fetch patient's billing records
  getBillingRecords: function(patientId) {
    var arr = [];
    var gr = new GlideRecord('u_billing');
    gr.addQuery('u_patient_id.u_number', patientId);
    gr.query();
    while (gr.next()) {
      arr.push({
        billing : gr.getDisplayValue('u_billing_id'),
        amount: gr.u_total_amount + ''
      });
    }
    return arr;
  },

  // h. Fetch patient's insurance policies
  getInsurancePolicies: function(patientId) {
    var arr = [];
    var gr = new GlideRecord('u_insurance');
    gr.addQuery('u_patient_id.u_number', patientId);
    gr.query();
    while (gr.next()) {
      arr.push({
        policy: gr.u_policy_number + '',
        status: gr.u_status + ''
      });
    }
    return arr;
  },
    type: 'PatientUtils'
};
